async function initiateAuthCodeFlowWithPKCE() {
  const state = generateRandomString(32);
  const codeVerifier = generateRandomString(128);
  const codeChallenge = await generateCodeChallenge(codeVerifier);
  
  sessionStorage.setItem('oauth_state', state);
  sessionStorage.setItem('code_verifier', codeVerifier);
  sessionStorage.setItem('auth_timestamp', Date.now().toString());
  
  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OAuthConfig.clientId,
    redirect_uri: OAuthConfig.redirectUri,
    scope: OAuthConfig.scope,
    state: state,
    code_challenge: codeChallenge,
    code_challenge_method: 'S256'
  });
  
  window.location.href = `${OAuthConfig.authorizationEndpoint}?${params.toString()}`;
}

async function exchangeCodeForToken(code) {
  const codeVerifier = sessionStorage.getItem('code_verifier');
  
  const response = await fetch('https://your-auth-server.com/oauth/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAuthConfig.redirectUri,
      client_id: OAuthConfig.clientId,
      code_verifier: codeVerifier
    })
  });
  
  if (!response.ok) {
    throw new Error('Token exchange failed');
  }
  
  return await response.json();
}

function handleCallback() {
  const params = new URLSearchParams(window.location.search);
  const code = params.get('code');
  const state = params.get('state');
  const error = params.get('error');
  
  if (error) {
    console.error('OAuth error:', error);
    sessionStorage.clear();
    return { error };
  }
  
  const savedState = sessionStorage.getItem('oauth_state');
  
  if (!state || state !== savedState) {
    console.error('State mismatch - possible CSRF attack');
    sessionStorage.clear();
    return { error: 'state_mismatch' };
  }
  
  const authTimestamp = parseInt(sessionStorage.getItem('auth_timestamp') || '0');
  const currentTime = Date.now();
  if (currentTime - authTimestamp > 600000) {
    console.error('Authentication timeout');
    sessionStorage.clear();
    return { error: 'timeout' };
  }
  
  if (code) {
    return exchangeCodeForToken(code)
      .then(tokenData => {
        sessionStorage.removeItem('oauth_state');
        sessionStorage.removeItem('code_verifier');
        sessionStorage.removeItem('auth_timestamp');
        
        const expiresAt = Date.now() + (tokenData.expires_in * 1000);
        
        sessionStorage.setItem('access_token', tokenData.access_token);
        sessionStorage.setItem('token_expires_at', expiresAt.toString());
        
        if (tokenData.refresh_token) {
          sessionStorage.setItem('refresh_token', tokenData.refresh_token);
        }
        
        if (tokenData.id_token) {
          sessionStorage.setItem('id_token', tokenData.id_token);
        }
        
        return { success: true, tokenData };
      })
      .catch(error => {
        console.error('Token exchange error:', error);
        sessionStorage.clear();
        return { error: 'token_exchange_failed' };
      });
  }
  
  return { error: 'no_code' };
}

function getAccessToken() {
  const token = sessionStorage.getItem('access_token');
  const expiresAt = parseInt(sessionStorage.getItem('token_expires_at') || '0');
  
  if (!token || Date.now() >= expiresAt) {
    return null;
  }
  
  return token;
}

function isAuthenticated() {
  return getAccessToken() !== null;
}

function logout() {
  sessionStorage.removeItem('access_token');
  sessionStorage.removeItem('token_expires_at');
  sessionStorage.removeItem('refresh_token');
  sessionStorage.removeItem('id_token');
  sessionStorage.removeItem('oauth_state');
  sessionStorage.removeItem('code_verifier');
  sessionStorage.removeItem('auth_timestamp');
}

async function refreshAccessToken() {
  const refreshToken = sessionStorage.getItem('refresh_token');
  
  if (!refreshToken) {
    throw new Error('No refresh token available');
  }
  
  const response = await fetch('https://your-auth-server.com/oauth/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAuthConfig.clientId
    })
  });
  
  if (!response.ok) {
    throw new Error('Token refresh failed');
  }
  
  const tokenData = await response.json();
  const expiresAt = Date.now() + (tokenData.expires_in * 1000);
  
  sessionStorage.setItem('access_token', tokenData.access_token);
  sessionStorage.setItem('token_expires_at', expiresAt.toString());
  
  if (tokenData.refresh_token) {
    sessionStorage.setItem('refresh_token', tokenData.refresh_token);
  }
  
  return tokenData;
}

// App.js
import React, { useState, useEffect } from 'react';

function App() {
  const [isAuth, setIsAuth] = useState(false);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const checkAuth = () => {
      const authenticated = isAuthenticated();
      setIsAuth(authenticated);
      
      if (authenticated) {
        const idToken = sessionStorage.getItem('id_token');
        if (idToken) {
          try {
            const payload = JSON.parse(atob(idToken.split('.')[1]));
            setUser(payload);
          } catch (e) {
            console.error('Failed to parse ID token', e);
          }
        }
      }
      
      setLoading(false);
    };

    checkAuth();
  }, []);

  const handleLogin = () => {
    initiateAuthCodeFlowWithPKCE();
  };

  const handleLogout = () => {
    logout();
    setIsAuth(false);
    setUser(null);
  };

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div className="App">
      <header>
        <h1>OAuth 2.0 Secure Authentication</h1>
      </header>
      
      {!isAuth ? (
        <div>
          <h2>Please log in</h2>
          <button onClick={handleLogin}>Login with OAuth</button>
        </div>
      ) : (
        <div>
          <h2>Welcome!</h2>
          {user && (
            <div>
              <p>Email: {user.email}</p>
              <p>Name: {user.name}</p>
            </div>
          )}
          <button onClick={handleLogout}>Logout</button>
        </div>
      )}
    </div>
  );
}

export default App;

// Callback.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

function Callback() {
  const navigate = useNavigate();
  const [error, setError] = useState(null);

  useEffect(() => {
    const processCallback = async () => {
      const result = await handleCallback();
      
      if (result.error) {
        setError(result.error);
        setTimeout(() => {
          navigate('/');
        }, 3000);
      } else if (result.success) {
        navigate('/');
      }
    };

    processCallback();
  }, [navigate]);

  if (error) {
    return (
      <div>
        <h2>Authentication Error</h2>
        <p>{error}</p>
        <p>Redirecting to home...</p>
      </div>
    );
  }

  return (
    <div>
      <h2>Processing authentication...</h2>
    </div>
  );
}

export default Callback;

